Напиши две строки, которые выведет код. Объяснение не требуется. Если не знаешь, ответ «Не знаю» допустим.

```js
const steps = [];

function run(callback) {
  steps.push('run');
  const value = callback();
  steps.push('done');
  return value;
}

const result = run(() => {
  steps.push('callback');
  return 3;
});

console.log(steps.join('>'));
console.log(result);
```

